import json, os, time, sys
from datetime import datetime, timezone
import requests

# Jira listener connector: polls Jira Cloud REST API v3 for issues in a project and stops when assignment changes to a specific user.
# Endpoints used (non-deprecated):
# - GET /rest/api/3/search (with JQL and optional expand=changelog)
# - GET /rest/api/3/user/search?query= (optional, to resolve email to accountId)

ISO_FMT = "%Y-%m-%dT%H:%M:%S.%fZ"
JQL_TS_FMT = "%Y-%m-%d %H:%M"  # JQL accepts quoted date-time in this format (server local time). We'll use UTC and let Jira interpret appropriately.

def load_connector_config(path="/run/connector.json"):
    try:
        with open(path, "r") as f:
            return json.load(f)
    except Exception as e:
        print(json.dumps({"error": f"Failed to load connector config: {e}"}), flush=True)
        sys.exit(1)

def http_session(email, api_token):
    s = requests.Session()
    s.auth = (email, api_token)
    s.headers.update({"Accept": "application/json", "User-Agent": "jira-listener-connector/1.0"})
    return s

def resolve_account_id(session, base_url, email):
    if not email:
        return None
    try:
        # Docs: GET /rest/api/3/user/search with 'query' parameter returns users matching string (name/email). Requires appropriate permissions.
        resp = session.get(f"{base_url}/rest/api/3/user/search", params={"query": email, "maxResults": 10}, timeout=30)
        if resp.status_code == 200:
            users = resp.json()
            for u in users:
                # Prefer exact email match if available
                if u.get("emailAddress") and u["emailAddress"].lower() == email.lower():
                    return u.get("accountId")
            # Fallback: take first result
            if users:
                return users[0].get("accountId")
        else:
            # Could be 403 if lacking permission; fall through to None
            pass
    except Exception:
        pass
    return None

def parse_updated(ts):
    # Jira 'updated' is ISO8601 Zulu, e.g., 2024-10-23T12:34:56.789+0000 or with 'Z'
    # We'll try multiple formats.
    for fmt in ["%Y-%m-%dT%H:%M:%S.%f%z", "%Y-%m-%dT%H:%M:%S.%fZ", "%Y-%m-%dT%H:%M:%S%z", "%Y-%m-%dT%H:%M:%SZ"]:
        try:
            dt = datetime.strptime(ts, fmt)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return dt.astimezone(timezone.utc)
        except Exception:
            continue
    return None

def fmt_jql_dt(dt_utc):
    # Format datetime for JQL quoted date-time
    return dt_utc.astimezone(timezone.utc).strftime(JQL_TS_FMT)

def search_issues(session, base_url, jql, fields, expand, page_size):
    start_at = 0
    while True:
        params = {"jql": jql, "maxResults": page_size, "startAt": start_at}
        if fields:
            params["fields"] = ",".join(fields)
        if expand:
            params["expand"] = ",".join(expand)
        resp = session.get(f"{base_url}/rest/api/3/search", params=params, timeout=60)
        if resp.status_code == 429:
            time.sleep(5)
            continue
        resp.raise_for_status()
        data = resp.json()
        issues = data.get("issues", [])
        for issue in issues:
            yield issue
        total = data.get("total", 0)
        start_at += len(issues)
        if start_at >= total or len(issues) == 0:
            break

def find_assignee_change(issue, target_account_id):
    # Examine changelog for assignee changes to target_account_id
    clog = issue.get("changelog") or {}
    histories = clog.get("histories") or []
    for h in histories:
        for item in h.get("items", []):
            if item.get("field") == "assignee":
                to_val = item.get("to")
                # For GDPR-compliant Cloud, 'to' for user fields should be accountId; fallback to 'toString' is display name
                if target_account_id and to_val == target_account_id:
                    return {"matched": True, "matchedAt": h.get("created")}
    return {"matched": False}

def main():
    cfg = load_connector_config()
    auth = cfg.get("auth", {})
    conf = cfg.get("configuration", {})

    base_url = conf.get("baseUrl")
    project_key = conf.get("projectKey")
    stop_account_id = conf.get("stopOnAssigneeAccountId")
    stop_email = conf.get("stopOnAssigneeEmail")
    include_fields = conf.get("includeFields") or ["summary", "description", "assignee", "updated", "created", "priority", "status", "reporter"]
    expand_changelog = bool(conf.get("expandChangelog", True))
    poll_interval = int(conf.get("pollIntervalSeconds", 5))
    max_duration = int(conf.get("maxDurationSeconds", 600))
    page_size = int(conf.get("pageSize", 50))
    jql_filter = conf.get("jqlFilter") or ""

    email = auth.get("email")
    api_token = auth.get("apiToken")

    errors = []
    if not base_url or not isinstance(base_url, str):
        errors.append("configuration.baseUrl is required")
    if not project_key:
        errors.append("configuration.projectKey is required")
    if not email or not api_token:
        errors.append("auth.email and auth.apiToken are required")
    if errors:
        print(json.dumps({"error": "; ".join(errors)}))
        return

    base_url = base_url.rstrip("/")
    session = http_session(email, api_token)

    # Resolve accountId from email if needed
    if not stop_account_id and stop_email:
        stop_account_id = resolve_account_id(session, base_url, stop_email)
    if not stop_account_id:
        print(json.dumps({"error": "Provide either configuration.stopOnAssigneeAccountId or configuration.stopOnAssigneeEmail (resolvable)."}))
        return

    start_time = datetime.now(timezone.utc)
    last_query_time = start_time
    aggregated = {}
    matched_issue_key = None
    matched_at_iso = None

    # Build static JQL base
    base_jql = f"project = {project_key}"
    if jql_filter:
        base_jql = f"{base_jql} AND ({jql_filter})"

    expand = ["changelog"] if expand_changelog else []

    try:
        while True:
            now = datetime.now(timezone.utc)
            elapsed = (now - start_time).total_seconds()
            if elapsed >= max_duration:
                break

            jql_time_str = fmt_jql_dt(last_query_time)
            jql = f"{base_jql} AND updated >= \"{jql_time_str}\" ORDER BY updated ASC"

            latest_seen_updated = last_query_time
            for issue in search_issues(session, base_url, jql, include_fields, expand, page_size):
                key = issue.get("key")
                fields = issue.get("fields", {})
                updated_str = fields.get("updated")
                updated_dt = parse_updated(updated_str) if updated_str else None
                if updated_dt and updated_dt > latest_seen_updated:
                    latest_seen_updated = updated_dt

                # Store aggregation
                aggregated[key] = {
                    "id": issue.get("id"),
                    "key": key,
                    "fields": fields,
                    "seenAt": datetime.now(timezone.utc).strftime(ISO_FMT)
                }

                # Stop condition via changelog
                if expand_changelog:
                    match = find_assignee_change(issue, stop_account_id)
                    if match.get("matched"):
                        matched_issue_key = key
                        matched_at_iso = match.get("matchedAt") or datetime.now(timezone.utc).strftime(ISO_FMT)
                        raise StopIteration

                # Fallback: current assignee equals target
                assignee = fields.get("assignee")
                if assignee and assignee.get("accountId") == stop_account_id:
                    matched_issue_key = key
                    matched_at_iso = datetime.now(timezone.utc).strftime(ISO_FMT)
                    raise StopIteration

            # Advance window
            last_query_time = latest_seen_updated
            time.sleep(max(1, poll_interval))
    except StopIteration:
        pass
    except requests.HTTPError as e:
        print(json.dumps({"error": f"HTTP error: {e}", "details": getattr(e, "response", None).text if getattr(e, "response", None) is not None else None}))
        return
    except Exception as e:
        print(json.dumps({"error": f"Unexpected error: {e}"}))
        return

    result = {
        "status": "ok",
        "projectKey": project_key,
        "stopped": matched_issue_key is not None,
        "stopReason": "assigneeMatched" if matched_issue_key else "timeout",
        "matchedIssueKey": matched_issue_key,
        "matchedAt": matched_at_iso,
        "issuesCollectedCount": len(aggregated),
        "collectedIssues": list(aggregated.values())
    }
    print(json.dumps(result), flush=True)

if __name__ == "__main__":
    main()
